#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
using namespace std;
const int MAXN=1e5+5;
ll k,a[MAXN],ans=0;
int n,r;
void two_pointer()
{
	for(int l=1;l<=n;++l)
	{
		while(r>=1&&stoll(to_string(a[r])+to_string(a[l]))>k)--r;
		ans+=r,ans-=(r>=l);
	}
}
int main(void)
{
	scanf("%d%lld",&n,&k);
	for(int i=1;i<=n;++i)scanf("%lld",a+i);
	sort(a+1,a+n+1);
	r=n;two_pointer();
	printf("%lld",ans);
	return false;
}
